import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';

interface DataRequest {
    _id: string;
    userWallet: string;
    docType: string;
    status: string;
    sharedHash?: string;
    sharedIpfs?: string;
    requestedAt: string;
}

const EntityDashboard: React.FC = () => {
    const [incomingApps, setIncomingApps] = useState<any[]>([]);
    const [selectedApp, setSelectedApp] = useState<any>(null);
    const { user, token } = useAuth();
    const { account, contract } = useBlockchain();

    useEffect(() => {
        if (token) {
            fetchIncomingApps();
        }
    }, [token]);

    const fetchIncomingApps = async () => {
        try {
            const res = await fetch('http://localhost:5000/api/verify/incoming', {
                headers: { 'x-auth-token': token || '' }
            });
            const data = await res.json();
            if (res.ok) setIncomingApps(data);
        } catch (err) {
            console.error(err);
        }
    };

    const verifyOnChain = async (app: any) => {
        if (!contract) return;
        setLoading(true);
        try {
            // Pick a hash to verify (usually they only have one primary doc for now)
            const hashToVerify = app.documentCIDs[0]?.fileHash;
            if (!hashToVerify) throw new Error('No document hash found');

            // 1. Blockchain TX
            const tx = await contract.institutionalVerify(app.user.walletAddress, hashToVerify);
            await tx.wait();

            // 2. Update Backend
            await fetch('http://localhost:5000/api/verify/update-status', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'x-auth-token': token || ''
                },
                body: JSON.stringify({
                    requestId: app._id,
                    status: 'approved'
                })
            });

            fetchIncomingApps();
            setSelectedApp(null);
        } catch (err: any) {
            console.error(err);
            alert(`Verification failed: ${err.message}`);
        } finally {
            setLoading(false);
        }
    };
    const [userWallet, setUserWallet] = useState('');
    const [docType, setDocType] = useState('Aadhar Card');
    const [requests, setRequests] = useState<DataRequest[]>([]);
    const [loading, setLoading] = useState(false);
    const [message, setMessage] = useState('');

    useEffect(() => {
        fetchMyRequests();
    }, []);

    const fetchMyRequests = async () => {
        try {
            const res = await fetch('http://localhost:5000/api/entity/my-requests', {
                headers: { 'x-auth-token': token || '' }
            });
            const data = await res.json();
            if (res.ok) setRequests(data);
        } catch (err) {
            console.error(err);
        }
    };

    const handleCreateRequest = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        setMessage('');

        try {
            const res = await fetch('http://localhost:5000/api/entity/request', {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'x-auth-token': token || ''
                },
                body: JSON.stringify({ userWallet, docType })
            });

            if (res.ok) {
                setMessage('Request sent successfully!');
                setUserWallet('');
                fetchMyRequests();
            } else {
                const data = await res.json();
                setMessage(`Error: ${data.message}`);
            }
        } catch (err) {
            setMessage('Failed to send request');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="fade-in" style={{ maxWidth: '1200px', margin: '0 auto' }}>
            <div style={{ marginBottom: '4rem' }}>
                <h1 style={{ fontSize: '3rem' }}>Institution Portal</h1>
                <p style={{ color: 'var(--text-secondary)', fontSize: '1.2rem' }}>
                    Authenticated as: <strong style={{ color: '#fff' }}>{user?.entityName || user?.username}</strong>
                </p>
            </div>

            <div style={{ display: 'grid', gridTemplateColumns: '1fr 2fr', gap: '2.5rem' }}>
                {/* Request Form */}
                <div className="glass" style={{ padding: '2.5rem', height: 'fit-content' }}>
                    <h3 style={{ marginBottom: '1.5rem' }}>New Data Request</h3>

                    {!user?.walletAddress && (
                        <div className="status-badge" style={{ background: 'rgba(255,165,0,0.1)', color: 'orange', border: '1px solid orange', marginBottom: '1.5rem', width: '100%', justifyContent: 'center' }}>
                            Action Required: Link your wallet in the Hub
                        </div>
                    )}

                    <form onSubmit={handleCreateRequest} style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem', opacity: user?.walletAddress ? 1 : 0.5, pointerEvents: user?.walletAddress ? 'all' : 'none' }}>
                        <div>
                            <label>User Wallet Address</label>
                            <input 
                                type="text" 
                                placeholder="0x..." 
                                value={userWallet}
                                onChange={(e) => setUserWallet(e.target.value)}
                                required
                            />
                        </div>
                        <div>
                            <label>Required Document</label>
                            <select 
                                value={docType}
                                onChange={(e) => setDocType(e.target.value)}
                                style={{ 
                                    width: '100%', 
                                    padding: '1rem', 
                                    background: 'rgba(255,255,255,0.05)', 
                                    border: '1px solid var(--card-border)',
                                    color: '#fff'
                                }}
                            >
                                <option value="Aadhar Card">Aadhar Card</option>
                                <option value="PAN Card">PAN Card</option>
                                <option value="Passport">Passport</option>
                                <option value="Driving License">Driving License</option>
                            </select>
                        </div>
                        <button type="submit" className="btn btn-primary" disabled={loading || !user?.walletAddress}>
                            {loading ? 'Sending...' : 'Request Verification'}
                        </button>
                    </form>
                    {message && (
                        <div style={{ 
                            marginTop: '1.5rem', 
                            padding: '1rem', 
                            borderRadius: '8px',
                            background: message.includes('Error') ? 'rgba(255,68,68,0.1)' : 'rgba(0,255,136,0.1)',
                            color: message.includes('Error') ? 'var(--error)' : 'var(--success)',
                            fontSize: '0.9rem',
                            textAlign: 'center',
                            border: `1px solid ${message.includes('Error') ? 'var(--error)' : 'var(--success)'}`
                        }}>
                            {message}
                        </div>
                    )}
                </div>

                {/* KYC Application Queue */}
                <div className="glass" style={{ padding: '2.5rem', marginBottom: '2.5rem' }}>
                    <h3 style={{ marginBottom: '2rem', borderLeft: '4px solid #fff', paddingLeft: '1rem' }}>Incoming KYC Applications</h3>
                    {incomingApps.length === 0 ? (
                        <p style={{ opacity: 0.5, textAlign: 'center', padding: '2rem' }}>No pending applications for your institution.</p>
                    ) : (
                        <div style={{ display: 'grid', gridTemplateColumns: selectedApp ? '1fr 1fr' : '1fr', gap: '2rem' }}>
                            <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                                {incomingApps.map(app => (
                                    <div 
                                        key={app._id} 
                                        className="glass" 
                                        style={{ 
                                            padding: '1.5rem', 
                                            cursor: 'pointer', 
                                            background: selectedApp?._id === app._id ? 'rgba(255,255,255,0.05)' : 'rgba(255,255,255,0.01)',
                                            border: selectedApp?._id === app._id ? '1px solid #fff' : '1px solid var(--card-border)'
                                        }}
                                        onClick={() => setSelectedApp(app)}
                                    >
                                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                                            <div>
                                                <div style={{ fontWeight: 600 }}>{app.user?.fullName}</div>
                                                <div style={{ fontSize: '0.8rem', opacity: 0.5 }}>{app.user?.walletAddress?.slice(0,12)}...</div>
                                            </div>
                                            <div className="status-badge" style={{ fontSize: '0.7rem' }}>{app.status.toUpperCase()}</div>
                                        </div>
                                    </div>
                                ))}
                            </div>

                            {selectedApp && (
                                <div className="glass fade-in" style={{ padding: '2.5rem', background: 'rgba(255,255,255,0.02)' }}>
                                    <h4 style={{ marginBottom: '1.5rem' }}>Review Application</h4>
                                    <div style={{ marginBottom: '2rem' }}>
                                        <label style={{ fontSize: '0.7rem', opacity: 0.5 }}>NAME</label>
                                        <div style={{ fontWeight: 600 }}>{selectedApp.user?.fullName}</div>
                                    </div>
                                    <div style={{ marginBottom: '2rem' }}>
                                        <label style={{ fontSize: '0.7rem', opacity: 0.5 }}>SUBMITTED DOCUMENTS</label>
                                        {selectedApp.documentCIDs.map((doc: any, i: number) => (
                                            <div key={i} className="glass" style={{ padding: '1rem', marginTop: '0.5rem', background: 'rgba(255,255,255,0.03)' }}>
                                                <div style={{ fontSize: '0.85rem' }}>{doc.fileName}</div>
                                                <div style={{ fontFamily: 'monospace', fontSize: '0.7rem', opacity: 0.4, marginTop: '0.3rem' }}>{doc.fileHash}</div>
                                            </div>
                                        ))}
                                    </div>

                                    <div style={{ display: 'flex', gap: '1rem' }}>
                                        <button 
                                            onClick={() => verifyOnChain(selectedApp)} 
                                            disabled={loading || selectedApp.status === 'approved'} 
                                            className="btn btn-primary"
                                            style={{ flex: 1 }}
                                        >
                                            {loading ? 'Committing...' : selectedApp.status === 'approved' ? 'Verified on Blockchain' : 'Verify & Commit to Ledger'}
                                        </button>
                                        <button 
                                            onClick={() => setSelectedApp(null)}
                                            className="btn btn-outline"
                                            style={{ flex: 0.5 }}
                                        >
                                            Close
                                        </button>
                                    </div>
                                </div>
                            )}
                        </div>
                    )}
                </div>

                {/* Registration Modal/Form for Non-Whitelisted entities */}
                {user?.role === 'entity' && !user?.onChainType && (
                    <div className="glass" style={{ padding: '2.5rem', marginTop: '2.5rem', gridColumn: 'span 2', border: '1px solid rgba(0,136,255,0.2)' }}>
                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
                            <div>
                                <h2 style={{ marginBottom: '0.5rem' }}>Institutional Onboarding</h2>
                                <p style={{ color: 'var(--text-secondary)' }}>You are not yet registered in the Global On-Chain Entity Registry.</p>
                            </div>
                            <div className="status-badge" style={{ background: 'rgba(0,136,255,0.1)', color: '#0088ff' }}>Status: {user?.registrationStatus?.toUpperCase() || 'NONE'}</div>
                        </div>

                        {user?.registrationStatus === 'pending' ? (
                            <div style={{ padding: '3rem', textAlign: 'center', background: 'rgba(255,255,255,0.02)', borderRadius: '12px' }}>
                                <div style={{ fontSize: '3rem', marginBottom: '1.5rem' }}>⏳</div>
                                <h3 style={{ marginBottom: '1rem' }}>Application Under Review</h3>
                                <p style={{ maxWidth: '500px', margin: '0 auto', opacity: 0.7 }}>
                                    Your institutional credentials have been submitted. The protocol administrator will verify your details and whitelist your wallet on-chain shortly.
                                </p>
                            </div>
                        ) : (
                            <form 
                                onSubmit={async (e) => {
                                    e.preventDefault();
                                    const formData = new FormData(e.currentTarget);
                                    const data = {
                                        onChainType: parseInt(formData.get('type') as string),
                                        apiEndpoint: formData.get('endpoint') as string
                                    };
                                    try {
                                        const res = await fetch('http://localhost:5000/api/entity/apply', {
                                            method: 'POST',
                                            headers: {
                                                'Content-Type': 'application/json',
                                                'x-auth-token': token || ''
                                            },
                                            body: JSON.stringify(data)
                                        });
                                        if (res.ok) window.location.reload();
                                    } catch (err) {
                                        console.error(err);
                                    }
                                }}
                                style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: '1.5rem', alignItems: 'flex-end' }}
                            >
                                <div>
                                    <label>Professional Entity Type</label>
                                    <select name="type" style={{ width: '100%', padding: '1rem', background: 'rgba(255,255,255,0.05)', border: '1px solid var(--card-border)', color: '#fff' }}>
                                        <option value="0">Bank</option>
                                        <option value="1">Crypto Exchange</option>
                                        <option value="2">Insurance Provider</option>
                                        <option value="3">Government Agency</option>
                                        <option value="5">DeFi Protocol</option>
                                    </select>
                                </div>
                                <div>
                                    <label>Management API Endpoint (Optional)</label>
                                    <input name="endpoint" type="text" placeholder="https://api.yourbank.com" />
                                </div>
                                <button type="submit" className="btn btn-primary" style={{ padding: '1.1rem' }}>
                                    Submit Registration Request
                                </button>
                            </form>
                        )}
                    </div>
                )}

                {/* Requests List */}
                <div className="glass" style={{ padding: '2.5rem' }}>
                    <h3 style={{ marginBottom: '1.5rem' }}>Pending & Verified Audits</h3>
                    {requests.length === 0 ? (
                        <div style={{ textAlign: 'center', opacity: 0.5, marginTop: '4rem' }}>
                            <p>You haven't initiated any requests yet.</p>
                        </div>
                    ) : (
                        <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                            {requests.map((req) => (
                                <div key={req._id} className="glass" style={{ padding: '1.5rem', background: 'rgba(255,255,255,0.02)' }}>
                                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
                                        <div style={{ fontFamily: 'monospace', fontSize: '0.9rem' }}>
                                            {req.userWallet}
                                        </div>
                                        <div className={`status-badge ${req.status === 'approved' ? 'status-verified' : ''}`} style={{ fontSize: '0.8rem' }}>
                                            {req.status.toUpperCase()}
                                        </div>
                                    </div>
                                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-end' }}>
                                        <div>
                                            <div style={{ fontSize: '0.7rem', color: 'var(--text-muted)', textTransform: 'uppercase' }}>Document Type</div>
                                            <div style={{ fontSize: '1.1rem', fontWeight: 600 }}>{req.docType}</div>
                                        </div>
                                        <div style={{ fontSize: '0.7rem', opacity: 0.5 }}>
                                            Requested: {new Date(req.requestedAt).toLocaleDateString()}
                                        </div>
                                    </div>

                                    {req.status === 'approved' && (
                                        <div style={{ marginTop: '1.5rem', padding: '1rem', background: 'rgba(0,0,0,0.3)', borderRadius: '8px' }}>
                                            <div style={{ marginBottom: '0.5rem' }}>
                                                <label style={{ fontSize: '0.7rem', opacity: 0.6 }}>On-Chain Hash Proof</label>
                                                <div style={{ fontFamily: 'monospace', fontSize: '0.8rem', wordBreak: 'break-all', color: 'var(--success)' }}>
                                                    {req.sharedHash}
                                                </div>
                                            </div>
                                            <div>
                                                <label style={{ fontSize: '0.7rem', opacity: 0.6 }}>IPFS CID</label>
                                                <div style={{ fontFamily: 'monospace', fontSize: '0.8rem', color: 'var(--text-secondary)' }}>
                                                    {req.sharedIpfs}
                                                </div>
                                                <a href={`https://gateway.pinata.cloud/ipfs/${req.sharedIpfs}`} target="_blank" rel="noreferrer" style={{ fontSize: '0.7rem', color: '#fff', textDecoration: 'underline' }}>
                                                    View Source Document
                                                </a>
                                            </div>
                                        </div>
                                    )}
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

export default EntityDashboard;
